def check_lipinski(mol_weight, logP, hbd, hba):
    """
    Check Lipinski's Rule of Five.
    """
    violations = []

    if mol_weight > 500:
        violations.append(f'MW={mol_weight} > 500')
    if logP > 5:
        violations.append(f'logP={logP} > 5')
    if hbd > 5:
        violations.append(f'HBD={hbd} > 5')
    if hba > 10:
        violations.append(f'HBA={hba} > 10')

    return {
        'passes': len(violations) <= 1,  # Allow 1 violation
        'violations': violations,
        'n_violations': len(violations)
    }
